def count_range_sum(nums: list[int], lower: int, upper: int) -> int:
    n = len(nums)
    prefix_sums = [0] * (n + 1)
    for i in range(n):
        prefix_sums[i+1] = prefix_sums[i] + nums[i]

    def merge_sort(left, right):
        if left >= right:
            return 0
        mid = (left + right) // 2
        count = merge_sort(left, mid) + merge_sort(mid + 1, right)

        p1 = left
        p2 = left
        for y in range(mid + 1, right + 1):
            while p1 <= mid and prefix_sums[p1] < prefix_sums[y] - upper:
                p1 += 1
            while p2 <= mid and prefix_sums[p2] <= prefix_sums[y] - lower:
                p2 += 1
            count += p2 - p1

        temp = []
        i, j = left, mid + 1
        while i <= mid and j <= right:
            if prefix_sums[i] <= prefix_sums[j]:
                temp.append(prefix_sums[i])
                i += 1
            else:
                temp.append(prefix_sums[j])
                j += 1
        while i <= mid:
            temp.append(prefix_sums[i])
            i += 1
        while j <= right:
            temp.append(prefix_sums[j])
            j += 1

        for k in range(len(temp)):
            prefix_sums[left + k] = temp[k]

        return count

    return merge_sort(0, n)
