def matrix_mult(A, B):
    return [
        [A[0][0]*B[0][0] + A[0][1]*B[1][0], A[0][0]*B[0][1] + A[0][1]*B[1][1]],
        [A[1][0]*B[0][0] + A[1][1]*B[1][0], A[1][0]*B[0][1] + A[1][1]*B[1][1]]
    ]

def matrix_power(M, n):
    result = [[1, 0], [0, 1]]
    base = M
    while n > 0:
        if n % 2 == 1:
            result = matrix_mult(result, base)
        base = matrix_mult(base, base)
        n //= 2
    return result

def fibonacci(n):
    if n == 0:
        return 0
    M = [[1, 1], [1, 0]]
    res = matrix_power(M, n)
    return res[0][1]

def pisano_period(m):
    if m == 1:
        return 1
    # We search for the smallest k > 0 such that M^k ≡ I (mod m)
    # M = [[1, 1], [1, 0]]
    # We compute M^k mod m iteratively to keep numbers small
    a, b, c, d = 1, 0, 0, 1  # Identity matrix
    x, y, z, w = 1, 1, 1, 0  # M matrix
    for k in range(1, 6 * m + 1):
        a, b, c, d = (a*x + b*z) % m, (a*y + b*w) % m, (c*x + d*z) % m, (c*y + d*w) % m
        if a == 1 and b == 0 and c == 0 and d == 1:
            return k
    return -1
