def serialize(root) -> str:
    if not root:
        return "N"
    res = []
    stack = [root]
    while stack:
        node = stack.pop()
        if node is None:
            res.append("N")
        else:
            val = node.val
            res.append("L")
            res.append(f"{len(val):020d}")
            res.append(val)
            stack.append(node.right)
            stack.append(node.left)
    return "".join(res)

def deserialize(data) -> 'TreeNode | None':
    if not data:
        return None

    idx = 0
    n = len(data)

    def get_next():
        nonlocal idx
        if idx >= n:
            return None
        if data[idx] == 'N':
            idx += 1
            return None
        elif data[idx] == 'L':
            idx += 1
            length = int(data[idx:idx+20])
            idx += 20
            val = data[idx:idx+length]
            idx += length
            return val
        return None

    root_val = get_next()
    if root_val is None:
        return None

    root = TreeNode(root_val)
    stack = [root]

    while stack:
        node = stack[-1]
        if node.left is None:
            val = get_next()
            if val is not None:
                node.left = TreeNode(val)
                stack.append(node.left)
        elif node.right is None:
            val = get_next()
            if val is not None:
                node.right = TreeNode(val)
                stack.append(node.right)
        else:
            stack.pop()

    return root

class DirectedGraph:
    def __init__(self, n: int):
        self.n = n
        self.graph = [[] for _ in range(n)]
        self.in_degree = [0] * n

    def add_edge(self, u: int, v: int) -> None:
        self.graph[u].append(v)
        self.in_degree[v] += 1

    def has_cycle(self) -> bool:
        deg = self.in_degree[:]
        q = [i for i in range(self.n) if deg[i] == 0]
        count = 0
        while q:
            u = q.pop()
            count += 1
            for v in self.graph[u]:
                deg[v] -= 1
                if deg[v] == 0:
                    q.append(v)
        return count != self.n

    def topological_sort(self) -> list[int] | None:
        deg = self.in_degree[:]
        q = [i for i in range(self.n) if deg[i] == 0]
        res = []
        while q:
            u = q.pop()
            res.append(u)
            for v in self.graph[u]:
                deg[v] -= 1
                if deg[v] == 0:
                    q.append(v)
        return res if len(res) == self.n else None

    def all_topological_sorts(self) -> list[list[int]]:
        if self.has_cycle():
            return []
        res = []
        in_deg = self.in_degree[:]
        used = [False] * self.n

        def backtrack(path):
            if len(path) == self.n:
                res.append(path[:])
                return
            candidates = [i for i in range(self.n) if not used[i] and in_deg[i] == 0]
            candidates.sort()
            for u in candidates:
                used[u] = True
                path.append(u)
                for v in self.graph[u]:
                    in_deg[v] -= 1
                backtrack(path)
                path.pop()
                used[u] = False
                for v in self.graph[u]:
                    in_deg[v] += 1

        backtrack([])
        return res

    def longest_path(self) -> int:
        if self.has_cycle():
            return -1
        if self.n == 0:
            return 0
        topo = self.topological_sort()
        dist = [0] * self.n
        for u in topo:
            for v in self.graph[u]:
                if dist[u] + 1 > dist[v]:
                    dist[v] = dist[u] + 1
        return max(dist)

