from typing import List, Tuple

@dataclass
class Event:
    start: float
    end: float
    title: str
    priority: int

class Calendar:
    def __init__(self):
        self._events: List[Event] = []

    def add_event(self, event: Event) -> List[Event]:
        if event.start >= event.end:
            raise ValueError("start must be less than end")

        overlaps = [e for e in self._events if e.start < event.end and e.end > event.start]
        if not overlaps:
            self._events.append(event)
            return []

        new_wins = all(event.priority > e.priority for e in overlaps)

        if new_wins:
            overlap_ids = {id(e) for e in overlaps}
            self._events = [e for e in self._events if id(e) not in overlap_ids]
            for e in overlaps:
                if e.start < event.start:
                    self._events.append(Event(e.start, event.start, e.title, e.priority))
                if e.end > event.end:
                    self._events.append(Event(event.end, e.end, e.title, e.priority))
            self._events.append(event)
            return overlaps
        else:
            overlap_intervals = [(max(e.start, event.start), min(e.end, event.end)) for e in overlaps]
            overlap_intervals.sort()
            merged = []
            for s, e in overlap_intervals:
                if merged and s <= merged[-1][1]:
                    merged[-1] = (merged[-1][0], max(merged[-1][1], e))
                else:
                    merged.append((s, e))

            fragments = []
            cur = event.start
            for s, e in merged:
                if cur < s:
                    fragments.append(Event(cur, s, event.title, event.priority))
                cur = max(cur, e)
            if cur < event.end:
                fragments.append(Event(cur, event.end, event.title, event.priority))

            for frag in fragments:
                self._events.append(frag)
            return fragments

    def get_events(self, start: float, end: float) -> List[Event]:
        res = [e for e in self._events if e.start < end and e.end > start]
        res.sort(key=lambda e: e.start)
        return res

    def free_slots(self, start: float, end: float, min_duration: float = 0) -> List[Tuple[float, float]]:
        if start >= end:
            return []
        overlaps = self.get_events(start, end)
        intervals = []
        for e in overlaps:
            s = max(e.start, start)
            e_end = min(e.end, end)
            if s < e_end:
                intervals.append((s, e_end))
        intervals.sort()
        merged = []
        for s, e in intervals:
            if merged and s <= merged[-1][1]:
                merged[-1] = (merged[-1][0], max(merged[-1][1], e))
            else:
                merged.append((s, e))

        slots = []
        cur = start
        for s, e in merged:
            if s > cur:
                dur = s - cur
                if dur >= min_duration:
                    slots.append((cur, s))
            cur = max(cur, e)
        if end > cur:
            dur = end - cur
            if dur >= min_duration:
                slots.append((cur, end))
        return slots

    def utilization(self, start: float, end: float) -> float:
        if start >= end:
            return 0.0
        slots = self.free_slots(start, end)
        occupied = (end - start) - sum(e - s for s, e in slots)
        return occupied / (end - start)
