import hashlib
import bisect

class ConsistentHashRing:
    def __init__(self, num_virtual_nodes: int = 150):
        self.num_virtual_nodes = num_virtual_nodes
        self._ring = []
        self._node_map = {}
        self._physical_nodes = set()

    def add_node(self, node_id: str) -> None:
        if node_id in self._physical_nodes:
            return
        for i in range(self.num_virtual_nodes):
            virtual_node = f"{node_id}#v{i}"
            hash_val = int(hashlib.md5(virtual_node.encode()).hexdigest(), 16)
            bisect.insort(self._ring, hash_val)
            self._node_map[hash_val] = node_id
        self._physical_nodes.add(node_id)

    def remove_node(self, node_id: str) -> None:
        if node_id not in self._physical_nodes:
            raise KeyError(f"Node {node_id} not found")
        self._ring = [h for h in self._ring if self._node_map[h] != node_id]
        self._node_map = {h: n for h, n in self._node_map.items() if n != node_id}
        self._physical_nodes.remove(node_id)

    def get_node(self, key: str) -> str | None:
        if not self._ring:
            return None
        key_hash = int(hashlib.md5(key.encode()).hexdigest(), 16)
        idx = bisect.bisect_right(self._ring, key_hash)
        if idx == len(self._ring):
            idx = 0
        return self._node_map[self._ring[idx]]

    def get_nodes_for_key(self, key: str, num_replicas: int = 3) -> list[str]:
        if not self._ring:
            return []
        key_hash = int(hashlib.md5(key.encode()).hexdigest(), 16)
        idx = bisect.bisect_right(self._ring, key_hash)
        if idx == len(self._ring):
            idx = 0
        seen = set()
        result = []
        n = len(self._ring)
        while len(result) < num_replicas and len(seen) < len(self._physical_nodes):
            node = self._node_map[self._ring[idx]]
            if node not in seen:
                seen.add(node)
                result.append(node)
            idx = (idx + 1) % n
        return result
